glsl3.vert:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
layout(std140) uniform CCLocal {
  highp mat4 cc_matWorld;
  highp mat4 cc_matWorldIT;
  highp vec4 cc_lightingMapUVParam;
  highp vec4 cc_localShadowBias;
  highp vec4 cc_reflectionProbeData1;
  highp vec4 cc_reflectionProbeData2;
  highp vec4 cc_reflectionProbeBlendData1;
  highp vec4 cc_reflectionProbeBlendData2;
};
in vec3 a_position;
in vec2 a_texCoord;
in vec4 a_color;
out vec2 v_uv;
out vec2 v_bguv;
out vec4 v_color;
vec4 vert () {
  vec4 pos = cc_matViewProj * cc_matWorld * vec4(a_position, 1.0);
  v_uv = a_texCoord;
  v_color = a_color;
  v_bguv = pos.xy / pos.w * 0.5 + 0.5;
  v_bguv.y = 1.0 - v_bguv.y;
  return pos;
}
void main() { gl_Position = vert(); }

glsl3.frag:
precision mediump float;
in vec2 v_uv;
in vec2 v_bguv;
in vec4 v_color;
uniform sampler2D MainTex;
uniform sampler2D cc_screenTexture;
layout(std140) uniform Constant {
  vec4 Tint1;
  vec4 Tint2;
  float Alpha;
};
vec3 ColorDodge(vec3 base, vec3 blend) {
  return base / (1.0 - blend);
}
vec4 frag () {
  vec4 mainColor = texture(cc_screenTexture, v_bguv);
  vec4 blendColor = texture(MainTex, v_uv) * v_color;
  blendColor.rgb += Tint1.rgb * Tint1.a;
  vec3 resultRGB = ColorDodge(mainColor.rgb, blendColor.rgb);
  resultRGB += Tint2.rgb * Tint2.a;
  return vec4(resultRGB, blendColor.a * Alpha);
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

glsl1.vert:
precision highp float;
uniform highp mat4 cc_matViewProj;
uniform highp mat4 cc_matWorld;
attribute vec3 a_position;
attribute vec2 a_texCoord;
attribute vec4 a_color;
varying vec2 v_uv;
varying vec2 v_bguv;
varying vec4 v_color;
vec4 vert () {
  vec4 pos = cc_matViewProj * cc_matWorld * vec4(a_position, 1.0);
  v_uv = a_texCoord;
  v_color = a_color;
  v_bguv = pos.xy / pos.w * 0.5 + 0.5;
  v_bguv.y = 1.0 - v_bguv.y;
  return pos;
}
void main() { gl_Position = vert(); }

glsl1.frag:
precision mediump float;
varying vec2 v_uv;
varying vec2 v_bguv;
varying vec4 v_color;
uniform sampler2D MainTex;
uniform sampler2D cc_screenTexture;
   uniform vec4 Tint1;
   uniform vec4 Tint2;
   uniform float Alpha;
vec3 ColorDodge(vec3 base, vec3 blend) {
  return base / (1.0 - blend);
}
vec4 frag () {
  vec4 mainColor = texture2D(cc_screenTexture, v_bguv);
  vec4 blendColor = texture2D(MainTex, v_uv) * v_color;
  blendColor.rgb += Tint1.rgb * Tint1.a;
  vec3 resultRGB = ColorDodge(mainColor.rgb, blendColor.rgb);
  resultRGB += Tint2.rgb * Tint2.a;
  return vec4(resultRGB, blendColor.a * Alpha);
}
void main() { gl_FragColor = frag(); }
